// Animações
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { y: 50, opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: { duration: 0.6, ease: "easeOut" }
  }
};

// Shimmer loading animation
const ShimmerContainer = styled.div`
  padding: 6rem 2rem;
  background-color: white;
  max-width: 1200px;
  margin: 0 auto;
`;

const ShimmerCard = styled.div`
  background-color: #f0f0f0;
  border-radius: 12px;
  padding: 2rem;
  height: 250px;
  position: relative;
  overflow: hidden;
  
  &::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(
      90deg,
      rgba(255, 255, 255, 0),
      rgba(255, 255, 255, 0.3),
      rgba(255, 255, 255, 0)
    );
    animation: shimmer 1.5s infinite;
  }
  
  @keyframes shimmer {
    0% {
      transform: translateX(-100%);
    }
    100% {
      transform: translateX(100%);
    }
  }
`;

const ShimmerGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 2.5rem;
`;

const ShimmerHeader = styled.div`
  width: 60%;
  height: 40px;
  background-color: #f0f0f0;
  margin: 0 auto 20px auto;
  border-radius: 8px;
  position: relative;
  overflow: hidden;
  
  &::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(
      90deg,
      rgba(255, 255, 255, 0),
      rgba(255, 255, 255, 0.3),
      rgba(255, 255, 255, 0)
    );
    animation: shimmer 1.5s infinite;
  }
`;

const Features = () => {
  const [isLoading, setIsLoading] = useState(true);
  
  // Simular um carregamento
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 1200);
    
    return () => clearTimeout(timer);
  }, []);
  
  const features = [
    {
      icon: <BsLightningCharge />,
      title: 'Automação de vendas',
      description: 'Use o Prospector para automatizar seu processo de vendas, desde a prospecção até o fechamento, com inteligência artificial avançada.'
    },
    {
      icon: <BsClockHistory />,
      title: 'Respostas rápidas',
      description: 'Atenda seus clientes em segundos, mesmo fora do horário comercial, com respostas precisas e personalizadas.'
    },
    {
      icon: <BsGraphUp />,
      title: 'Análise de dados',
      description: 'Obtenha insights valiosos sobre seus clientes e vendas com análises avançadas e relatórios detalhados.'
    },
    {
      icon: <BsChatDots />,
      title: 'Chatbot inteligente',
      description: 'Um assistente virtual poderoso que entende linguagem natural e aprende com cada interação.'
    },
    {
      icon: <BsMegaphone />,
      title: 'Disparo de mensagens em massa',
      description: 'Alcance milhares de potenciais clientes de uma só vez com campanhas personalizadas e segmentadas.'
    },
    {
      icon: <BsFunnel />,
      title: 'Funil de vendas integrado',
      description: 'Gerencie todas as etapas do seu funil em um só lugar, com automação inteligente para maximizar conversões.'
    }
  ];
  
  if (isLoading) {
    return (
      <FeaturesSection>
        <ShimmerContainer>
          <ShimmerHeader />
          <ShimmerHeader style={{ width: '40%', height: '20px', marginBottom: '60px' }} />
          
          <ShimmerGrid>
            {Array(6).fill(0).map((_, index) => (
              <ShimmerCard key={index} />
            ))}
          </ShimmerGrid>
        </ShimmerContainer>
      </FeaturesSection>
    )
  }
  
  return (
    <FeaturesSection id="features">
      <FeaturesHeader>
        <Title
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          Recursos Prospector que transformam sua estratégia de vendas
        </Title>
        <Subtitle
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
        >
          Conheça as funcionalidades do Prospector que estão revolucionando o atendimento e as vendas
          das empresas mais inovadoras do mercado.
        </Subtitle>
      </FeaturesHeader>
      
      <Grid
        variants={containerVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.1 }}
      >
        {features.map((feature, index) => (
          <FeatureCard 
            key={index}
            variants={itemVariants}
            whileHover={{ y: -5 }}
            transition={{ type: 'spring', stiffness: 300 }}
          >
            <IconContainer>
              {feature.icon}
            </IconContainer>
            <FeatureTitle>{feature.title}</FeatureTitle>
            <FeatureDescription>{feature.description}</FeatureDescription>
          </FeatureCard>
        ))}
      </Grid>
    </FeaturesSection>
  );
};

export default Features; 
